exercises.solution_code:
#include <algorithm>
#include <iostream>
#include <vector>

struct AbsCompare
{
    bool operator()(int a, int b) const
    {
        int absA{ a < 0 ? -a : a };
        int absB{ b < 0 ? -b : b };
        return absA < absB;
    }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> v(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    std::stable_sort(v.begin(), v.end(), AbsCompare{});

    for (int i{ 0 }; i < n; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << v[i];
    }
    std::cout << '\n';

    return 0;
}
